{
  "grammar": [
    {
      "pattern": "常常 + Verb + Object",
      "structure": ["常常", "Verb", "Object"],
      "explanation_en": "Use '常常' (chángcháng) to express that an action happens frequently or often. It is placed before the verb phrase.",
      "title": "Expressing Frequency with 常常",
      "meaning": "Often do something",
      "when_to_use": ["When talking about hobbies you do regularly", "When describing routines or habits"],
      "when_not_to_use": ["For actions that happen only once or rarely", "In negative sentences (use 不常 instead)"],
      "pragmatic_notes": "In Taiwan, 常常 is commonly used in casual conversation about free time activities. It is neutral and polite.",
      "word_order_notes": "常常 must come before the verb, not at the end of the sentence.",
      "english_contrast": "In English, 'often' can be placed before or after the verb (e.g., 'I often play basketball' or 'I play basketball often'). In Chinese, 常常 always goes before the verb.",
      "korean_contrast": "In Korean, '자주' (jaju) is similar and also placed before the verb, but Korean word order is SOV, while Chinese is SVO.",
      "negative_examples": [
        {
          "text": "我常常不運動。",
          "error": "Incorrect: 常常 is not used with negatives. Use 不常 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我打籃球常常。",
          "error": "Incorrect: 常常 must come before the verb, not after the object."
        }
      ],
      "transformation_drills": ["Change '我打籃球' to '我常常打籃球' to add frequency.", "Change '他看小說' to '他常常看小說'."],
      "production_drills": ["Say you often listen to music.", "Say your friend often plays tennis."],
      "common_error_patterns": ["Placing 常常 after the verb or object", "Using 常常 with negative verbs"],
      "repair_feedback": {
        "word_order": "Remember: 常常 goes before the verb, e.g., '我常常看小說'.",
        "politeness": "This structure is neutral and polite in all contexts.",
        "vocabulary": "Use 常常 for frequent actions; for rare actions, use 很少."
      }
    },
    {
      "pattern": "有時候 + Verb + Object",
      "structure": ["有時候", "Verb", "Object"],
      "explanation_en": "Use '有時候' (yǒu shíhou) to express that an action happens sometimes or occasionally. It is placed before the verb phrase.",
      "title": "Expressing Occasional Actions with 有時候",
      "meaning": "Sometimes do something",
      "when_to_use": ["When talking about hobbies you do occasionally", "When describing activities that are not regular"],
      "when_not_to_use": ["For actions that are always true", "For actions that never happen (use 從來不 instead)"],
      "pragmatic_notes": "In Taiwan, 有時候 is very common in casual speech. It can also be used at the beginning of a sentence for emphasis.",
      "word_order_notes": "有時候 can be placed at the beginning of the sentence or before the verb. Both are correct.",
      "english_contrast": "In English, 'sometimes' can be placed at the beginning, middle, or end of a sentence. In Chinese, 有時候 is usually at the beginning or before the verb.",
      "korean_contrast": "In Korean, '가끔' (gakkeum) is similar and can be placed at the beginning or before the verb, similar to Chinese.",
      "negative_examples": [
        {
          "text": "我沒有有時候看電影。",
          "error": "Incorrect: 有時候 is not used with 沒有. Use 不常 or 很少 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我看電影有時候。",
          "error": "Incorrect: 有時候 should come before the verb or at the beginning of the sentence."
        }
      ],
      "transformation_drills": ["Change '我爬山' to '我有时候爬山' to add occasional frequency.", "Change '他聽廣播' to '他有时候聽廣播'."],
      "production_drills": ["Say you sometimes play chess.", "Say your friend sometimes goes camping."],
      "common_error_patterns": ["Placing 有時候 after the verb or object", "Using 有時候 in negative sentences"],
      "repair_feedback": {
        "word_order": "Place 有時候 at the beginning or before the verb, e.g., '有時候我爬山' or '我有时候爬山'.",
        "politeness": "This structure is neutral and polite.",
        "vocabulary": "Use 有時候 for occasional actions; for frequent actions, use 常常."
      }
    },
    {
      "pattern": "喜歡 + Verb + Object",
      "structure": ["喜歡", "Verb", "Object"],
      "explanation_en": "Use '喜歡' (xǐhuān) to express liking or enjoying an activity. It is followed directly by a verb phrase.",
      "title": "Expressing Hobbies with 喜歡",
      "meaning": "Like to do something",
      "when_to_use": ["When talking about hobbies or activities you enjoy", "When asking about someone's interests"],
      "when_not_to_use": ["For actions you dislike (use 不喜歡 instead)", "For actions you do out of necessity (use 需要 instead)"],
      "pragmatic_notes": "In Taiwan, 喜歡 is very common for discussing hobbies. It can be used with both verbs and nouns (e.g., 喜歡看小說, 喜歡咖啡).",
      "word_order_notes": "喜歡 must be followed by a verb or noun. Do not place a subject between 喜歡 and the verb.",
      "english_contrast": "In English, 'like' can be followed by a gerund or infinitive (e.g., 'I like reading' or 'I like to read'). In Chinese, 喜歡 is always followed by a verb without any change.",
      "korean_contrast": "In Korean, '좋아하다' (joahada) is similar and is followed by a noun with the object particle, but Chinese uses a verb directly.",
      "negative_examples": [
        {
          "text": "我喜歡不運動。",
          "error": "Incorrect: 喜歡 cannot be negated with 不 after it. Use 不喜歡 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喜歡打籃球常常。",
          "error": "Incorrect: 喜歡 is followed by the verb phrase; frequency words like 常常 go before 喜歡 or after the verb."
        }
      ],
      "transformation_drills": ["Change '我打籃球' to '我喜歡打籃球' to express enjoyment.", "Change '他看小說' to '他喜歡看小說'."],
      "production_drills": ["Say you like to play tennis.", "Say your friend likes to watch baseball games."],
      "common_error_patterns": ["Placing frequency words between 喜歡 and the verb", "Using 喜歡 with negative verbs incorrectly"],
      "repair_feedback": {
        "word_order": "Place 喜歡 directly before the verb, e.g., '我喜歡打籃球'.",
        "politeness": "This structure is neutral and polite for discussing interests.",
        "vocabulary": "Use 喜歡 for enjoyment; for necessity, use 需要."
      }
    }
  ]
}
